                if cell == 1:
                    rect = pygame.Rect(preview_x * BLOCK_SIZE + x * BLOCK_SIZE, preview_y * BLOCK_SIZE + y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE)
                    pygame.draw.rect(screen, self.next_block.color, rect)

