            for x, cell in enumerate(row):
                if cell == 1:
                    if self.current_block.y + y >= GRID_HEIGHT or self.current_block.x + x < 0 or self.current_block.x + x >= GRID_WIDTH or self.grid[self.current_block.y + y][self.current_block.x + x] > 0:
                        return True
        return False

    def lock_block(self):
        for y, row in enumerate(self.current_block.shape[self.current_block.rotation]):
            for x, cell in enumerate(row):
                if cell == 1:
                    self.grid[self.current_block.y + y][self.current_block.x + x] = self.current_block.color

    def clear_lines(self):
        lines_cleared = 0
        for y in range(GRID_HEIGHT - 1, -1, -1):
            if all(self.grid[y]):
                del self.grid[y]
                self.grid.insert(0, [0] * GRID_WIDTH)
                lines_cleared += 1

        for i, player in enumerate(self.players):
            if lines_cleared > 0:
                player.score += 10 * lines_cleared * (i + 1)

    def check_game_over(self):
        for x in range(GRID_WIDTH):
            if self.grid[0][x] > 0:
