import pygame
import random

# Define the game dimensions
GAME_WIDTH = 10
GAME_HEIGHT = 20
BLOCK_SIZE = 30

# Define the tetromino shapes
TETROMINOS = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[1, 1, 1], [0, 1, 0]],  # T
    [[1, 1, 1], [1, 0, 0]],  # L
    [[1, 1, 1], [0, 0, 1]],  # J
    [[1, 1, 0], [0, 1, 1]],  # S
    [[0, 1, 1], [1, 1, 0]]  # Z
]

# Define the colors for the tetrominos
TETROMINO_COLORS = [(0, 255, 255), (255, 255, 0), (255, 0, 255), (255, 128, 0), (0, 0, 255), (0, 255, 0), (255, 0, 0)]

class Tetromino:
    def __init__(self, game, player_index):
        self.game = game
        self.player_index = player_index
        self.shape = random.choice(TETROMINOS)
        self.color = TETROMINO_COLORS[player_index]
        self.x = 3
        self.y = 0
        self.rotation = 0

    def move_left(self):
        if self.game.can_move(self.x - 1, self.y, self.shape, self.rotation, self.player_index):
            self.x -= 1

    def move_right(self):
        if self.game.can_move(self.x + 1, self.y, self.shape, self.rotation, self.player_index):
            self.x += 1

    def move_down(self):
        if self.game.can_move(self.x, self.y + 1, self.shape, self.rotation, self.player_index):
            self.y += 1
        else:
            self.game.lock_tetromino(self.x, self.y, self.shape, self.rotation, self.player_index)
            self.game.spawn_tetromino(self.player_index)

    def rotate(self):
        new_rotation = (self.rotation + 1) % len(self.shape)
        if self.game.can_move(self.x, self.y, self.shape, new_rotation, self.player_index):
            self.rotation = new_rotation

class Game:
    def __init__(self):
        self.players = [Player(self, i) for i in range(3)]
        self.game_board = [[[0 for _ in range(GAME_WIDTH)] for _ in range(GAME_HEIGHT)] for _ in range(3)]
        self.tetrominos = [Tetromino(self, i) for i in range(3)]
        self.score = [0] * 3

    def can_move(self, x, y, shape, rotation, player_index):
        for i in range(len(shape[rotation])):
            for j in range(len(shape[rotation][i])):
                if shape[rotation][i][j] == 1:
                    if x + j < 0 or x + j >= GAME_WIDTH or y + i >= GAME_HEIGHT or self.game_board[player_index][y + i][x + j] != 0:
                        return False
        return True

    def lock_tetromino(self, x, y, shape, rotation, player_index):
        for i in range(len(shape[rotation])):
            for j in range(len(shape[rotation][i])):
                if shape[rotation][i][j] == 1:
                    self.game_board[player_index][y + i][x + j] = 1

    def spawn_tetromino(self, player_index):
        self.tetrominos[player_index] = Tetromino(self, player_index)

