        lines_cleared = 0
        for y in range(GAME_HEIGHT):
            if all(self.game_board[player_index][y]):
                self.game_board[player_index].pop(y)
                self.game_board[player_index].insert(0, [0] * GAME_WIDTH)
                lines_cleared += 1
        self.score[player_index] += lines_cleared ** 2 * 100
        return lines_cleared

    def update(self):
        for player in self.players:
            player.update()

    def draw(self, screen):
        for player_index in range(3):
            for y in range(GAME_HEIGHT):
                for x in range(GAME_WIDTH):
                    if self.game_board[player_index][y][x] == 1:
                        pygame.draw.rect(screen, TETROMINO_COLORS[player_index], (x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
