import pygame
import random

# Tetris game constants
BLOCK_SIZE = 30
GRID_WIDTH = 10
GRID_HEIGHT = 20
WINDOW_WIDTH = GRID_WIDTH * BLOCK_SIZE
WINDOW_HEIGHT = GRID_HEIGHT * BLOCK_SIZE

# Tetris piece shapes
PIECES = [
    [(0, 0), (0, 1), (1, 0), (1, 1)],  # Square
    [(0, 0), (0, 1), (0, 2), (0, 3)],  # I-piece
    [(0, 0), (0, 1), (0, 2), (1, 2)],  # L-piece
    [(0, 0), (0, 1), (0, 2), (1, 0)],  # J-piece
    [(0, 0), (0, 1), (1, 0), (1, 1)],  # T-piece
    [(0, 0), (0, 1), (1, 1), (1, 2)],  # S-piece
    [(0, 0), (0, 1), (1, 0), (1, 1)],  # Z-piece
]

# Colors for the Tetris pieces
COLORS = [(255, 0, 0), (0, 255, 0), (0, 0, 255), (255, 255, 0), (255, 0, 255), (0, 255, 255), (128, 128, 128)]

class TetrisBoard:
    def __init__(self, player_num):
        self.player_num = player_num
        self.grid = [[0 for _ in range(GRID_WIDTH)] for _ in range(GRID_HEIGHT)]
        self.score = 0
        self.level = 1
        self.current_piece = self.get_new_piece()
        self.next_piece = self.get_new_piece()
        self.fall_time = 0
        self.fall_speed = 0.5

    def get_new_piece(self):
        return random.choice(PIECES), COLORS[self.player_num]

    def rotate_piece(self):
        new_piece = [(y, -x) for x, y in self.current_piece[0]]
        if all(0 <= x < GRID_WIDTH and 0 <= y < GRID_HEIGHT and self.grid[y][x] == 0 for x, y in new_piece):
            self.current_piece[0] = new_piece

    def move_piece(self, dx, dy):
        new_piece = [(x + dx, y + dy) for x, y in self.current_piece[0]]
        if all(0 <= x < GRID_WIDTH and 0 <= y < GRID_HEIGHT and self.grid[y][x] == 0 for x, y in new_piece):
            self.current_piece[0] = new_piece

    def drop_piece(self):
        while self.can_move_down():
            self.move_piece(0, 1)
        self.lock_piece()

    def can_move_down(self):
        new_piece = [(x, y + 1) for x, y in self.current_piece[0]]
        return all(0 <= x < GRID_WIDTH and 0 <= y < GRID_HEIGHT and self.grid[y][x] == 0 for x, y in new_piece)

    def lock_piece(self):
        for x, y in self.current_piece[0]:
            self.grid[y][x] = self.current_piece[1]
        self.clear_lines()
        self.current_piece = self.next_piece
        self.next_piece = self.get_new_piece()

    def clear_lines(self):
        lines_cleared = 0
        for y in range(GRID_HEIGHT - 1, -1, -1):
            if all(self.grid[y][x] != 0 for x in range(GRID_WIDTH)):
                self.grid.pop(y)
                self.grid.insert(0, [0] * GRID_WIDTH)
                lines_cleared += 1
        if lines_cleared > 0:
            self.score += lines_cleared ** 2 * 100
            self.level = self.score // 1000 + 1
            self.fall_speed = max(0.1, 0.5 - 0.05 * (self.level - 1))

class TetrisGame:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((WINDOW_WIDTH * 3, WINDOW_HEIGHT))
        pygame.display.set_caption("Tetris")
        self.clock = pygame.time.Clock()
        self.boards = [TetrisBoard(i) for i in range(3)]

    def run(self):
        running = True
        while running:
            self.clock.tick(30)
            self.handle_events()
            self.update_game()
            self.render_game()

    def handle_events(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                pygame.quit()
                quit()
            elif event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT:
                    self.boards[0].move_piece(-1, 0)
                elif event.key == pygame.K_RIGHT:
                    self.boards[0].move_piece(1, 0)
                elif event.key == pygame.K_DOWN:
                    self.boards[0].move_piece(0, 1)
                elif event.key == pygame.K_UP:
                    self.boards[0].rotate_piece()
                elif event.key == pygame.K_a:
                    self.boards[1].move_piece(-1, 0)
                elif event.key == pygame.K_d:
                    self.boards[1].move_piece(1, 0)
                elif event.key == pygame.K_s:
                    self.boards[1].move_piece(0, 1)
                elif event.key == pygame.K_w:
                    self.boards[1].rotate_piece()
                elif event.key == pygame.K_j:
                    self.boards[2].move_piece(-1, 0)
                elif event.key == pygame.K_l:
                    self.boards[2].move_piece(1, 0)
                elif event.key == pygame.K_k:
                    self.boards[2].move_piece(0, 1)
                elif event.key == pygame.K_i:
                    self.boards[2].rotate_piece()

    def update_game(self):
        for board in self.boards:
            board.fall_time += self.clock.get_time()
            if board.fall_time > 1000 * board.fall_speed:
                board.fall_time = 0
                if not board.can_move_down():
                    board.lock_piece()

    def render_game(self):
        self.screen.fill((0, 0, 0))
        for i, board in enumerate(self.boards):
            self.render_board(board, i)
        pygame.display.flip()

    def render_board(self, board, index):
        x_offset = index * WINDOW_WIDTH
        for y in range(GRID_HEIGHT):
            for x in range(GRID_WIDTH):
                if board.grid[y][x] != 0:
                    pygame.draw.rect(self.screen, board.grid[y][x], (x * BLOCK_SIZE + x_offset, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
        for x, y in board.current_piece[0]:
            pygame.draw.rect(self.screen, board.current_piece[1], (x * BLOCK_SIZE + x_offset, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
        self.render_score(board, x_offset)

    def render_score(self, board, x_offset):
        font = pygame.font.Font(None, 36)
        text = font.render(f"Player {board.player_num} - Score: {board.score} - Level: {board.level}", True, (255, 255, 255))
        self.screen.blit(text, (x_offset + 10, GRID_HEIGHT * BLOCK_SIZE + 10))

if __name__ == "__main__":
    game = TetrisGame()
    game.run()

