PLAYER_COLORS = [(255, 0, 0), (0, 255, 0), (0, 0, 255)]

# Define Tetromino shapes
TETROMINO_SHAPES = [
    [(0, 0), (0, 1), (1, 0), (1, 1)],  # Square
    [(0, 0), (0, 1), (0, 2), (0, 3)],  # I-shape
    [(0, 0), (0, 1), (0, 2), (1, 2)],  # L-shape
    [(0, 0), (0, 1), (0, 2), (1, 0)],  # J-shape
    [(0, 0), (0, 1), (1, 1), (1, 0)],  # T-shape
    [(0, 0), (0, 1), (1, 1), (1, 2)],  # S-shape
    [(0, 0), (0, 1), (1, 0), (1, 1)]   # Z-shape
]

class Tetromino:
    def __init__(self, shape, color):
        self.shape = shape
        self.color = color
        self.x = 3
        self.y = 0
        self.rotation = 0

    def rotate(self):
        self.rotation = (self.rotation + 1) % 4
        self.shape = TETROMINO_SHAPES[(TETROMINO_SHAPES.index(self.shape) + 1) % len(TETROMINO_SHAPES)]

    def move_left(self):
        self.x -= 1

    def move_right(self):
        self.x += 1

    def move_down(self):
        self.y += 1

class Player:
    def __init__(self, name, color):
        self.name = name
        self.color = color
        self.score = 0
        self.current_tetromino = Tetromino(random.choice(TETROMINO_SHAPES), self.color)

    def update_score(self, lines_cleared):
        self.score += lines_cleared * 100

class TetrisGame:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((WINDOW_WIDTH, WINDOW_HEIGHT))
        pygame.display.set_caption("Tetris")
        self.clock = pygame.time.Clock()
        self.players = [
            Player("Player 1", PLAYER_COLORS[0]),
            Player("Player 2", PLAYER_COLORS[1]),
            Player("Player 3", PLAYER_COLORS[2])
        ]
        self.grid = [[0 for _ in range(GRID_COLS)] for _ in range(GRID_ROWS)]

    def run(self):
        running = True
        while running:
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    running = False

            self.update()
            self.draw()
            self.clock.tick(60)

        pygame.quit()

    def update(self):
        for player in self.players:
            # Move the player's current tetromino down
            player.current_tetromino.move_down()

            # Check for collisions
            if self.check_collision(player.current_tetromino):
                player.current_tetromino.move_up()
                self.lock_tetromino(player.current_tetromino)
                player.current_tetromino = Tetromino(random.choice(TETROMINO_SHAPES), player.color)

            # Check for completed lines
            lines_cleared = self.clear_completed_lines()
            player.update_score(lines_cleared)

    def draw(self):
        self.screen.fill((0, 0, 0))

        # Draw the grid
        for y in range(GRID_ROWS):
            for x in range(GRID_COLS):
                if self.grid[y][x] != 0:
                    pygame.draw.rect(self.screen, self.grid[y][x], (x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))

        # Draw the players' current tetrominos
        for player in self.players:
