                pygame.draw.rect(self.screen, player.color, (x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))

        # Draw the players' scores
        for i, player in enumerate(self.players):
            score_text = f"{player.name}: {player.score}"
            self.screen.blit(pygame.font.Font(None, 36).render(score_text, True, player.color), (10, 10 + i * 30))

        pygame.display.flip()

    def check_collision(self, tetromino):
        for block in tetromino.shape:
            x = tetromino.x + block[0]
            y = tetromino.y + block[1]
            if x < 0 or x >= GRID_COLS or y >= GRID_ROWS or self.grid[y][x] != 0:
                return True
        return False

    def lock_tetromino(self, tetromino):
        for block in tetromino.shape:
            x = tetromino.x + block[0]
            y = tetromino.y + block[1]
            self.grid[y][x] = tetromino.color

    def clear_completed_lines(self):
        lines_cleared = 0
        for y in range(GRID_ROWS - 1, -1, -1):
            if all(self.grid[y]):
                self.grid.pop(y)
                self.grid.insert(0, [0] * GRID_COLS)
                lines_cleared += 1
        return lines_cleared

