import random

class Tetromino:
    SHAPES = [
        [[1, 1, 1, 1]],  # I
        [[1, 1], [1, 1]],  # O
        [[1, 1, 1], [0, 1, 0]],  # T
        [[1, 1, 1], [1, 0, 0]],  # L
        [[1, 1, 1], [0, 0, 1]],  # J
        [[1, 1, 0], [0, 1, 1]],  # S
        [[0, 1, 1], [1, 1, 0]]  # Z
    ]

    def __init__(self, x, y, shape_index):
        self.x = x
        self.y = y
        self.shape = self.SHAPES[shape_index]
        self.color = (random.randint(50, 255), random.randint(50, 255), random.randint(50, 255))

    def rotate(self):
        self.shape = [list(reversed(col)) for col in zip(*self.shape)]

    def move_down(self):
        self.y += 1

    def move_left(self):
        self.x -= 1

    def move_right(self):
        self.x += 1

class Board:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[0 for _ in range(width)] for _ in range(height)]
        self.current_tetromino = None
        self.score = [0, 0, 0]

    def add_tetromino(self, tetromino):
        self.current_tetromino = tetromino

    def update(self):
        if self.current_tetromino:
            self.clear_tetromino()
            self.current_tetromino.move_down()
            if self.check_collision():
                self.lock_tetromino()
                self.clear_lines()
                self.add_tetromino(Tetromino(3, 0, random.randint(0, len(Tetromino.SHAPES) - 1)))
            else:
                self.draw_tetromino()

    def clear_tetromino(self):
        for y, row in enumerate(self.current_tetromino.shape):
            for x, cell in enumerate(row):
                if cell:
                    self.grid[y + self.current_tetromino.y][x + self.current_tetromino.x] = 0

    def draw_tetromino(self):
        for y, row in enumerate(self.current_tetromino.shape):
            for x, cell in enumerate(row):
                if cell:
                    self.grid[y + self.current_tetromino.y][x + self.current_tetromino.x] = self.current_tetromino.color

    def lock_tetromino(self):
        for y, row in enumerate(self.current_tetromino.shape):
            for x, cell in enumerate(row):
                if cell:
                    self.grid[y + self.current_tetromino.y][x + self.current_tetromino.x] = self.current_tetromino.color
        self.current_tetromino = None

    def check_collision(self):
        for y, row in enumerate(self.current_tetromino.shape):
            for x, cell in enumerate(row):
                if cell:
                    if y + self.current_tetromino.y >= self.height or x + self.current_tetromino.x < 0 or x + self.current_tetromino.x >= self.width or self.grid[y + self.current_tetromino.y][x + self.current_tetromino.x]:
                        return True
        return False

    def clear_lines(self):
        for y in range(self.height - 1, -1, -1):
            if all(self.grid[y]):
                del self.grid[y]
                self.grid.insert(0, [0] * self.width)
                for i in range(3):
                    self.score[i] += 10

class Game:
