import random
import pygame

# Define the game window size
WINDOW_WIDTH = 800
WINDOW_HEIGHT = 600

# Define the block size
BLOCK_SIZE = 30

# Define the game grid size
GRID_WIDTH = 10
GRID_HEIGHT = 20

# Define the number of players
NUM_PLAYERS = 3

# Define the colors
COLORS = [(255, 0, 0), (0, 255, 0), (0, 0, 255)]

# Define the Tetromino shapes
TETROMINOS = [
    [(0, 0), (0, 1), (1, 0), (1, 1)],  # Square
    [(0, 0), (0, 1), (0, 2), (0, 3)],  # Line
    [(0, 0), (0, 1), (0, 2), (1, 1)],  # T-shape
    [(0, 0), (0, 1), (1, 0), (1, 1)],  # Z-shape
    [(0, 0), (0, 1), (0, 2), (1, 2)],  # L-shape
    [(0, 0), (0, 1), (0, 2), (1, 0)],  # J-shape
    [(0, 0), (0, 1), (1, 1), (1, 2)]   # S-shape
]

class Tetromino:
    def __init__(self, x, y, shape, color):
        self.x = x
        self.y = y
        self.shape = shape
        self.color = color

    def rotate(self):
        self.shape = [(y, -x) for x, y in self.shape]

    def move(self, dx, dy):
        self.x += dx
        self.y += dy

class Player:
    def __init__(self, index):
        self.index = index
        self.score = 0
        self.grid = [[0 for _ in range(GRID_WIDTH)] for _ in range(GRID_HEIGHT)]
        self.current_tetromino = None
        self.next_tetromino = self.get_random_tetromino()

    def get_random_tetromino(self):
        shape = random.choice(TETROMINOS)
        return Tetromino(3, 0, shape, COLORS[self.index])

    def update(self):
        if self.current_tetromino is None:
            self.current_tetromino = self.next_tetromino
            self.next_tetromino = self.get_random_tetromino()

        # Move the current tetromino down
        self.current_tetromino.move(0, 1)

        # Check for collisions
        if self.check_collision(self.current_tetromino):
            self.current_tetromino.move(0, -1)
            self.lock_tetromino()
            self.current_tetromino = None

    def lock_tetromino(self):
        for x, y in self.current_tetromino.shape:
            tx = self.current_tetromino.x + x
            ty = self.current_tetromino.y + y
            if ty < 0 or ty >= GRID_HEIGHT or tx < 0 or tx >= GRID_WIDTH:
                continue
            self.grid[ty][tx] = self.current_tetromino.color

        self.clear_lines()

    def clear_lines(self):
        cleared_lines = 0
        for y in range(GRID_HEIGHT):
            if all(self.grid[y]):
                self.grid.pop(y)
                self.grid.insert(0, [0 for _ in range(GRID_WIDTH)])
                cleared_lines += 1

        if cleared_lines > 0:
            self.score += 10 * cleared_lines ** 2

    def check_collision(self, tetromino):
        for x, y in tetromino.shape:
            tx = tetromino.x + x
            ty = tetromino.y + y
            if ty < 0 or ty >= GRID_HEIGHT or tx < 0 or tx >= GRID_WIDTH or self.grid[ty][tx] != 0:
                return True
        return False

class Game:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((WINDOW_WIDTH, WINDOW_HEIGHT))
        pygame.display.set_caption("Tetris")
        self.players = [Player(i) for i in range(NUM_PLAYERS)]

    def run(self):
        clock = pygame.time.Clock()
        running = True
        while running:
            clock.tick(30)
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    running = False

            # Update the game state
            for player in self.players:
                player.update()

            # Draw the game
            self.screen.fill((0, 0, 0))
            for i, player in enumerate(self.players):
                self.draw_player_grid(player, i)
                self.draw_player_score(player, i)
            pygame.display.flip()

        pygame.quit()

    def draw_player_grid(self, player, index):
        x = index * (GRID_WIDTH * BLOCK_SIZE + 50) + 50
        y = 50
        for row in player.grid:
            for cell in row:
                if cell != 0:
                    pygame.draw.rect(self.screen, cell, (x, y, BLOCK_SIZE, BLOCK_SIZE))
                x += BLOCK_SIZE
            y += BLOCK_SIZE
            x = index * (GRID_WIDTH * BLOCK_SIZE + 50) + 50

        if player.current_tetromino:
            for x, y in player.current_tetromino.shape:
                px = x + player.current_tetromino.x
                py = y + player.current_tetromino.y
                pygame.draw.rect(self.screen, player.current_tetromino.color, (index * (GRID_WIDTH * BLOCK_SIZE + 50) + px * BLOCK_SIZE + 50, py * BLOCK_SIZE + 50, BLOCK_SIZE, BLOCK_SIZE))

    def draw_player_score(self, player, index):
        font = pygame.font.Font(None, 36)
        text = font.render(f"Player {index + 1} Score: {player.score}", True, (255, 255, 255))
        self.screen.blit(text, (index * (GRID_WIDTH * BLOCK_SIZE + 50) + 50, 20))

if __name__ == "__main__":
    game = Game()
    game.run()

