        for block in self.shape:
            x = self.x + block[0]
            y = self.y + block[1]
            rect = (x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE)
            pygame.draw.rect(self.game.screen, self.color, rect)

